command:
// Sci-fi mind-altering — purple ray that drifts, evoking cognitive expansion.
if (!game.modules.get("tokenmagic")?.active) return;
if (!token) return;
const filterId = "fishut-tmfx-scifi-mind-altering";
if (mode === "remove") { await TokenMagic.deleteFiltersOnToken(token, filterId); return; }
await TokenMagic.addUpdateFiltersOnToken(token, [{
  filterType: "ray",
  filterId,
  color: 0x8c30ff,
  time: 0,
  intensity: 2,
  amplitude: 1,
  blend: 8,
  divergence: 5,
  animated: { time: { active: true, speed: 0.0008, animType: "move" } }
}]);
